# Invocation REELLE du compilateur Solidity avec SMTChecker
# (Stop & Repair : la version precedente hardcodait une sortie supposee "reelle".
#  On invoque maintenant le vrai binaire solc et on affiche sa sortie effective.
#  Le .sol est ecrit en chemin relatif (cwd) pour garder une sortie propre, sans
#  chemin machine - regle secrets-hygiene case A : on corrige la source, jamais la sortie.)
import subprocess, os, shutil

def _locate_solc() -> str:
    """Localise le binaire solc installe (solcx, puis PATH)."""
    try:
        import solcx
        if hasattr(solcx, "get_executable"):
            return solcx.get_executable("0.8.28")
        # solcx ancienne API : construire le chemin depuis le dossier d'installation
        bin_dir = os.path.join(solcx.get_solcx_install_folder(), "solc-v0.8.28")
        for name in ("solc.exe", "solc"):
            cand = os.path.join(bin_dir, name)
            if os.path.isfile(cand):
                return cand
    except Exception:
        pass
    return shutil.which("solc") or "solc"

def run_smtchecker(contract_code: str, label: str) -> None:
    """Invoque le vrai solc avec le model checker SMT et affiche sa sortie reelle."""
    rel_path = "sc14_smtcheck.sol"
    with open(rel_path, "w", encoding="utf-8") as f:
        f.write(contract_code)
    try:
        solc_bin = _locate_solc()
        print(f"=== {label} ===")
        print(f"$ {os.path.basename(solc_bin)} --model-checker-engine all {rel_path}\n")
        try:
            res = subprocess.run(
                [solc_bin, "--model-checker-engine", "all", rel_path],
                capture_output=True, text=True, timeout=120,
            )
        except FileNotFoundError:
            print("[solc introuvable : installer solc (solcx install_solc 0.8.28) pour executer SMTChecker]")
            return
        # SMTChecker emet ses diagnostics (warnings/contre-exemples) sur stderr
        diag = (res.stderr + ("\n" + res.stdout if res.stdout.strip() else "")).strip()
        print(diag if diag else "(compilation reussie, aucun diagnostique)")
        print(f"\n[code de sortie solc : {res.returncode}]")
    finally:
        if os.path.exists(rel_path):
            os.unlink(rel_path)

# 1) Contrat sain : checks-effects-interactions respecte (etat mis a jour AVANT le transfer)
run_smtchecker(vault_smt_code, "Contrat VaultSMT (sain)")

