    if SOLC_VERSION not in installed:
        solcx.install_solc(SOLC_VERSION)
    solcx.set_solc_version(SOLC_VERSION)

    compiled = solcx.compile_source(
        STORAGE_CONTRACT, output_values=["abi", "bin"], solc_version=SOLC_VERSION
    )
